if (Satellites.getFlagHintsVisible()) {
    core.debug("Satellite hints are visible");
}

if (Satellites.getFlagLabelsVisible()) {
    core.debug("Satellite labels are visible");
}

// Show satellite labels
Satellites.setFlagLabelsVisible(true);

// Hide satellite labels
Satellites.setFlagLabelsVisible(false);

// Increase label size for better readability
Satellites.setLabelFontSize(14);

// Reset to default
Satellites.setLabelFontSize(10);

if (Satellites.getFlagOrbitLines()) {
    core.debug("Satellite orbit lines are visible");
}

// Show satellite orbits
Satellites.setFlagOrbitLines(true);

// Hide orbits for cleaner view
Satellites.setFlagOrbitLines(false);

if (Satellites.getFlagIconicMode()) {
    core.debug("Iconic mode is active");
}

// Use simplified icons for better performance
Satellites.setFlagIconicMode(true);

// Use standard satellite icons
Satellites.setFlagIconicMode(false);

if (Satellites.getFlagHideInvisible()) {
    core.debug("Only visible satellites are shown");
}

// Show only satellites above horizon
Satellites.setFlagHideInvisible(true);

// Show all satellites regardless of visibility
Satellites.setFlagHideInvisible(false);

if (Satellites.getFlagColoredInvisible()) {
    core.debug("Invisible satellites have special color");
}

// Mark invisible satellites with darker color
Satellites.setFlagColoredInvisible(true);

// Use same color for all satellites
Satellites.setFlagColoredInvisible(false);

// Read color using property
var colorStr = core.getStelProperty('Satellites.invisibleSatelliteColor');
var parts = colorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);
core.debug("Invisible color: RGB(" + r + ", " + g + ", " + b + ")");

// Write using method
var newColor = core.vec3f(0.3, 0.05, 0.05);
Satellites.setInvisibleSatelliteColor(newColor);

if (Satellites.getUpdatesEnabled()) {
    core.debug("Automatic satellite TLE updates are enabled");
}

// Enable automatic satellite data updates
Satellites.setUpdatesEnabled(true);

// Disable automatic updates (use offline data only)
Satellites.setUpdatesEnabled(false);

// Update daily
Satellites.setUpdateFrequencyHours(24);

// Update weekly
Satellites.setUpdateFrequencyHours(168);

// Manually update satellite orbital data
Satellites.updateFromOnlineSources();
core.debug("Satellite update started...");

// Wait for update to complete
core.wait(30);
core.debug("Satellite update completed");

// Save to default location
Satellites.saveCatalog();

// Save to custom location
Satellites.saveCatalog("/home/user/satellites_backup.json");
core.debug("Satellite catalog saved");

var iss = Satellites.getById("25544");
if (iss) {
    core.debug("Found ISS");
    core.moveToObject(iss.getEnglishName(), 3);
}

// Get all visible satellites
var sats = Satellites.getSatellites("", 0);
core.debug("Visible satellites: " + sats.keys().length);

// Get all Starlink satellites
var starlink = Satellites.getSatellites("starlink", 2);
for (var id in starlink) {
    core.debug(starlink[id] + " (NORAD: " + id + ")");
}

var groups = Satellites.getGroups();
core.debug("Available satellite groups: " + groups.values().join(", "));

// Check if a group exists
if (groups.contains("starlink")) {
    core.debug("Starlink satellites are available");
}

var allIds = Satellites.listAllIds();
core.debug("Total satellites in catalog: " + allIds.length);

// Check if a specific satellite exists
if (allIds.indexOf("25544") >= 0) {
    core.debug("ISS is in the catalog");
}

var objects = Satellites.listAllObjects(false);
core.debug("Total satellites: " + objects.length);

// Print first 10 satellite names
for (var i = 0; i < Math.min(10, objects.length); i++) {
    core.debug(objects[i].first);
}

// Search by name
var iss = Satellites.searchByName("ISS");
if (iss) {
    core.debug("Found: " + iss.getEnglishName());
    core.moveToObject(iss.getEnglishName(), 2);
}

// Search by NORAD number
var hst = Satellites.searchByName("NORAD 20580");
if (hst) {
    core.debug("Found Hubble Space Telescope");
}

// Search with current language name
var sat = Satellites.searchByNameI18n("محطة الفضاء الدولية");
if (sat) {
    core.debug("Found satellite");
}

var iss = Satellites.searchByID("25544");
if (iss) {
    core.debug("ISS found!");
    core.moveToObject(iss.getEnglishName(), 3);
}

var lastId = Satellites.getLastSelectedSatelliteID();
if (lastId) {
    var sat = Satellites.getById(lastId);
    if (sat) {
        core.debug("Last selected: " + sat.getEnglishName());
    }
}
